const body = $input.first().json.body ?? $input.first().json;

// Only process text replies, not new image messages
const isText = !!body.message?.textMessage || !!body.message?.conversation;
if (!isText) return [];

// Skip messages sent by the bot itself
if (body.fromMe) return [];

const phone = body.phone;
const messageText = (body.message?.textMessage?.text ?? body.message?.conversation ?? '').trim();
if (!phone || !messageText) return [];

return [{ json: { phone, messageText } }];

const job = $input.first().json;
if (!job.jobId) return []; // No pending job found for this phone

const resumeUrl = job.resumeWebhookUrl;
const suggestedPrice = parseFloat(job.suggestedPrice ?? 0);
const messageText = $('Code: Parse WhatsApp Reply').first().json.messageText.toLowerCase().trim();

// Parse price from text. Examples: "350", "R$ 350", "350,00", "350.00", "ok"
let price = suggestedPrice;
let action = 'approve';

if (messageText === 'rejeitar' || messageText === 'cancelar' || messageText === 'nao' || messageText === 'não') {
  action = 'reject';
} else if (messageText !== 'ok' && messageText !== 'sim') {
  const match = messageText.match(/[\d]+[.,]?[\d]*/);
  if (match) {
    price = parseFloat(match[0].replace(',', '.'));
  }
}

if (action === 'approve' && (!price || price <= 0)) {
  // Cannot parse price — reply asking for a valid value
  return [{ json: { _invalid: true, phone: job.phone } }];
}

return [{ json: { resumeUrl, price, action, jobId: job.jobId, phone: job.phone, _invalid: false } }];
